}

export interface RexStats {
  total: number;
  withEmail: number;
  withPrice: number;
  avgPrice: number;
  materials: Record<string, number>;
  despatch: Record<string, number>;
  sources: Record<string, number>;
  dailyCounts: { date: string; label: string; count: number }[];
  recentLeads: LeadEvent[];
  trackingSince: string | null;
}

// ── Helpers ───────────────────────────────────────────────────────────────────

function brisbaneDateString(offset = 0): string {
  const d = new Date(Date.now() + offset * 24 * 60 * 60 * 1000);
  // Brisbane is UTC+10
  return new Date(d.getTime() + 10 * 60 * 60 * 1000)
    .toISOString()
    .slice(0, 10);
}

export function parsePriceValue(raw: string | undefined | null): number {
  if (!raw || raw === "Not quoted") return 0;
  const m = raw.match(/[\d,]+\.?\d*/);
  if (!m) return 0;
  return parseFloat(m[0].replace(/,/g, ""));
}

const MATERIAL_PATTERNS: [RegExp, string][] = [
  [/mirror\s*acrylic|euomir|prismatic/i,  "Mirror Acrylic"],
  [/acrylic/i,                             "Acrylic"],
  [/polycarbonate|poly\s*carb\b/i,        "Polycarbonate"],
  [/seaboard/i,                            "Seaboard HDPE"],
  [/playground/i,                          "Playground HDPE"],
  [/hdpe|high[\s-]density|cutting board/i, "HDPE"],
  [/acetal|pom[\s-]c/i,                    "Acetal"],
  [/ptfe|teflon/i,                         "PTFE"],
  [/uhmwpe|uhmw/i,                         "UHMWPE"],
  [/nylon|pa[\s-]?6/i,                     "Nylon"],
  [/polypropylene\b/i,                     "Polypropylene"],
  [/petg/i,                                "PETG"],
  [/hips/i,                                "HIPS"],
  [/peek/i,                                "PEEK"],
  [/corflute/i,                            "Corflute"],
  [/acp|alumin/i,                          "ACP"],
  [/pvc/i,                                 "PVC"],
];

export function extractMaterial(text: string | undefined | null): string | null {
  if (!text) return null;
  for (const [re, name] of MATERIAL_PATTERNS) {
    if (re.test(text)) return name;
  }
  return null;
}

// ── Track a lead event ────────────────────────────────────────────────────────

export async function trackLead(event: LeadEvent): Promise<void> {
  const redis = getRedis();
  if (!redis) return;

  const today = brisbaneDateString();
  const priceVal = event.priceValue ?? parsePriceValue(event.price);

  try {
    const pipeline = redis.pipeline();

    // Global counters
    pipeline.incr(K.total);
    if (event.email) pipeline.incr(K.withEmail);
    if (priceVal > 0) {
      pipeline.incr(K.withPrice);
      pipeline.incrbyfloat(K.priceSum, priceVal);
      pipeline.incr(K.priceCount);
    }

    // Daily bucket (expires after 90 days)
    pipeline.incr(K.day(today));
    pipeline.expire(K.day(today), 90 * 24 * 60 * 60);

    // Hashes
    if (event.material) pipeline.hincrby(K.materials, event.material, 1);
    if (event.despatch) pipeline.hincrby(K.despatch, event.despatch, 1);
    if (event.source)   pipeline.hincrby(K.sources, event.source, 1);

    // Recent leads list — store full email for dashboard display
    const record: LeadEvent = {
      timestamp:  event.timestamp,
      source:     event.source,
      name:       event.name,
      email:      event.email,
      emailHash:  event.emailHash, // privacy-safe matching key
      price:      event.price,
      priceValue: priceVal > 0 ? priceVal : undefined,
      material:   event.material,
      despatch:   event.despatch,
      summary:    event.summary,
    };
    pipeline.lpush(K.recent, JSON.stringify(record));
    pipeline.ltrim(K.recent, 0, 99); // keep last 100

    await pipeline.exec();
  } catch {
    // Never throw — this is analytics, not critical path
  }
}

// ── Fetch all stats for the dashboard ────────────────────────────────────────

export async function fetchRexStats(): Promise<RexStats> {
  const redis = getRedis();

  const empty: RexStats = {
    total: 0, withEmail: 0, withPrice: 0, avgPrice: 0,
    materials: {}, despatch: {}, sources: {},
    dailyCounts: buildEmptyDays(),
    recentLeads: [],
    trackingSince: null,
  };

  if (!redis) return empty;

  try {
    // Daily keys for last 30 days
    const days = Array.from({ length: 30 }, (_, i) => brisbaneDateString(-i));

    const [
      total, withEmail, withPrice, priceSum, priceCount,
      materials, despatch, sources, recentRaw,
      ...dailyRaw
    ] = await Promise.all([
      redis.get<number>(K.total),
      redis.get<number>(K.withEmail),
      redis.get<number>(K.withPrice),
      redis.get<string>(K.priceSum),
      redis.get<number>(K.priceCount),
      redis.hgetall<Record<string, number>>(K.materials),
      redis.hgetall<Record<string, number>>(K.despatch),
      redis.hgetall<Record<string, number>>(K.sources),
      redis.lrange<string>(K.recent, 0, 19),
      ...days.map(d => redis.get<number>(K.day(d))),
    ]);

    const totalVal    = total    ?? 0;
    const emailVal    = withEmail ?? 0;
    const priceVal    = withPrice ?? 0;
    const priceSumVal = parseFloat(String(priceSum ?? "0")) || 0;
    const priceCountV = priceCount ?? 0;
    const avgPrice    = priceCountV > 0 ? Math.round(priceSumVal / priceCountV) : 0;

    const dailyCounts = days.map((date, i) => ({
      date,
      label: formatDayLabel(date),
      count: (dailyRaw[i] as number | null) ?? 0,
    })).reverse(); // oldest first for chart

    const recentLeads: LeadEvent[] = (recentRaw ?? []).map(r => {
      try { return typeof r === "string" ? JSON.parse(r) : r; } catch { return null; }
    }).filter(Boolean) as LeadEvent[];

    // First lead date from recentLeads (rough proxy for tracking start)
    const oldest = recentLeads[recentLeads.length - 1]?.timestamp ?? null;

    return {
      total: totalVal,
      withEmail: emailVal,
      withPrice: priceVal,
      avgPrice,
      materials: materials ?? {},
      despatch:  despatch  ?? {},
      sources:   sources   ?? {},
      dailyCounts,
      recentLeads,
      trackingSince: oldest,
    };
  } catch {
    return empty;
  }
}

function buildEmptyDays() {
  return Array.from({ length: 30 }, (_, i) => {
    const date = brisbaneDateString(-(29 - i));
    return { date, label: formatDayLabel(date), count: 0 };
  });
}

function formatDayLabel(dateStr: string): string {
  const d = new Date(dateStr + "T00:00:00+10:00");
  return d.toLocaleDateString("en-AU", { day: "numeric", month: "short" });
}

// ── Feedback CRUD ─────────────────────────────────────────────────────────────

export async function trackFeedback(item: FeedbackItem): Promise<void> {
  const redis = getRedis();
  if (!redis) return;
  try {
    const pipeline = redis.pipeline();
    pipeline.hset(K.feedbackHash, { [item.id]: JSON.stringify(item) });
    pipeline.lpush(K.feedbackIds, item.id);
    pipeline.ltrim(K.feedbackIds, 0, 199); // keep last 200
    await pipeline.exec();
  } catch { /* never throw */ }
}

export async function fetchFeedback(): Promise<FeedbackItem[]> {
  const redis = getRedis();
  if (!redis) return [];
  try {
    const all = await redis.hgetall(K.feedbackHash) as Record<string, string> | null;
    if (!all) return [];
    const items = Object.values(all)
      .map(v => { try { return typeof v === "string" ? JSON.parse(v) as FeedbackItem : null; } catch { return null; } })
      .filter(Boolean) as FeedbackItem[];
    // Sort newest first (ID is prefixed with timestamp)
    items.sort((a, b) => new Date(b.submittedAt).getTime() - new Date(a.submittedAt).getTime());
    return items.slice(0, 200);
  } catch { return []; }
}

export async function updateFeedback(id: string, updates: Partial<FeedbackItem>): Promise<void> {
  const redis = getRedis();
  if (!redis) return;
  try {
    const raw = await redis.hget(K.feedbackHash, id) as string | null;
    if (!raw) return;
    const item = JSON.parse(raw) as FeedbackItem;
    const updated = { ...item, ...updates };
    await redis.hset(K.feedbackHash, { [id]: JSON.stringify(updated) });
  } catch { /* never throw */ }
}

// ── Weekly digest data ────────────────────────────────────────────────────────

export interface WeeklyWindow {
  leads: number;          // total lead events
  withEmail: number;      // leads with email captured
  withPrice: number;      // leads with a quoted price
  quotedRevenue: number;  // sum of all quoted values (AUD)
  avgQuote: number;       // avg quoted price (priced leads only)
  emailCaptureRate: number; // 0-100
  topMaterials: Array<{ name: string; count: number }>;
  byDay: Array<{ date: string; label: string; count: number }>; // 7 days Mon→Sun
  emailHashes: string[];  // SHA-256 hashes for this week's leads — used for WooCommerce order attribution
}

export interface WeeklyDigestData {
  thisWeek: WeeklyWindow;
  lastWeek: Pick<WeeklyWindow, "leads" | "withEmail" | "withPrice" | "quotedRevenue">;
  allTime: { total: number; withEmail: number; avgPrice: number };
  generatedAt: string; // ISO string — Brisbane time
}

export async function fetchWeeklyDigestData(): Promise<WeeklyDigestData> {
  const redis = getRedis();

  const now = Date.now();
  const msPerDay = 24 * 60 * 60 * 1000;

  // Last 14 day keys (this week + last week)
  const days14 = Array.from({ length: 14 }, (_, i) => brisbaneDateString(-(13 - i)));
  const thisWeekDates = days14.slice(7);  // most recent 7
  const lastWeekDates = days14.slice(0, 7);

  const thisWeekSet = new Set(thisWeekDates);
  const lastWeekSet = new Set(lastWeekDates);

  // Fetch day buckets + all-time stats + recent leads (100) in parallel
  const [
    totalAll, withEmailAll, withPriceAll, priceSumAll, priceCountAll,
    recentRaw,
    ...dayRaw
  ] = await Promise.all([
    redis!.get<number>(K.total),
    redis!.get<number>(K.withEmail),
    redis!.get<number>(K.withPrice),
    redis!.get<string>(K.priceSum),
    redis!.get<number>(K.priceCount),
    redis!.lrange<string>(K.recent, 0, 99),
    ...days14.map(d => redis!.get<number>(K.day(d))),
  ]);

  // All-time aggregates
  const totalVal    = totalAll ?? 0;
  const emailVal    = withEmailAll ?? 0;
  const priceCountV = priceCountAll ?? 0;
  const priceSumVal = parseFloat(String(priceSumAll ?? "0")) || 0;
  const avgPriceAll = priceCountV > 0 ? Math.round(priceSumVal / priceCountV) : 0;

  // Day bucket counts split by week
  const dayCountsByDate: Record<string, number> = {};
  days14.forEach((d, i) => { dayCountsByDate[d] = (dayRaw[i] as number | null) ?? 0; });

  const thisWeekLeads = thisWeekDates.reduce((s, d) => s + dayCountsByDate[d], 0);
  const lastWeekLeads = lastWeekDates.reduce((s, d) => s + dayCountsByDate[d], 0);

  const thisWeekByDay = thisWeekDates.map(d => ({
    date: d,
    label: new Date(d + "T00:00:00+10:00").toLocaleDateString("en-AU", { weekday: "short" }),
    count: dayCountsByDate[d],
  }));

  // Detailed stats from recent leads list (newest first)
  const recentLeads: LeadEvent[] = (recentRaw ?? []).map(r => {
    try { return typeof r === "string" ? JSON.parse(r) : r; } catch { return null; }
  }).filter(Boolean) as LeadEvent[];

  // Filter to this week's leads
  const thisWeekStart = new Date(Date.now() - 7 * msPerDay).toISOString();
  const thisWeekLeadsDetail = recentLeads.filter(l => l.timestamp >= thisWeekStart);
  const lastWeekStart = new Date(Date.now() - 14 * msPerDay).toISOString();
  const lastWeekLeadsDetail = recentLeads.filter(l => l.timestamp >= lastWeekStart && l.timestamp < thisWeekStart);

  function windowFrom(leads: LeadEvent[], totalFromBuckets?: number): WeeklyWindow {
    const withEmail = leads.filter(l => l.email).length;
    const priced    = leads.filter(l => (l.priceValue ?? 0) > 0);
    const revenue   = priced.reduce((s, l) => s + (l.priceValue ?? 0), 0);
    const avgQuote  = priced.length > 0 ? Math.round(revenue / priced.length) : 0;
    const total     = totalFromBuckets ?? leads.length;
    const emailRate = total > 0 ? Math.round((withEmail / total) * 100) : 0;

    // Top materials
    const matCounts: Record<string, number> = {};
    for (const l of leads) {
      if (l.material) matCounts[l.material] = (matCounts[l.material] ?? 0) + 1;
    }
    const topMaterials = Object.entries(matCounts)
      .sort((a, b) => b[1] - a[1])
      .slice(0, 3)
      .map(([name, count]) => ({ name, count }));

    // Collect email hashes for WooCommerce attribution matching
    const emailHashes = leads.map(l => l.emailHash).filter((h): h is string => !!h);

    return { leads: total, withEmail, withPrice: priced.length, quotedRevenue: revenue, avgQuote, emailCaptureRate: emailRate, topMaterials, byDay: [], emailHashes };
  }

  const thisWeek: WeeklyWindow = {
    ...windowFrom(thisWeekLeadsDetail, thisWeekLeads),
    byDay: thisWeekByDay,
  };

  const lastWeekSummary = windowFrom(lastWeekLeadsDetail, lastWeekLeads);

  return {
    thisWeek,
    lastWeek: { leads: lastWeekSummary.leads, withEmail: lastWeekSummary.withEmail, withPrice: lastWeekSummary.withPrice, quotedRevenue: lastWeekSummary.quotedRevenue },
    allTime: { total: totalVal, withEmail: emailVal, avgPrice: avgPriceAll },
    generatedAt: new Date().toISOString(),
  };
}

// ── Transcript storage ────────────────────────────────────────────────────────

export interface TranscriptMessage {
  role: "user" | "assistant";
  content: string;
}

export async function storeTranscript(
  timestamp: string,
  messages: TranscriptMessage[]
): Promise<void> {
  const redis = getRedis();
  if (!redis) return;
  try {
    const key = K.transcript(timestamp);
    await redis.set(key, JSON.stringify(messages), { ex: 90 * 24 * 3600 }); // 90-day TTL
  } catch { /* never throw */ }
}

export async function fetchTranscript(
  timestamp: string
): Promise<TranscriptMessage[] | null> {
  const redis = getRedis();
  if (!redis) return null;
  try {
    const raw = await redis.get(K.transcript(timestamp)) as string | null;
    if (!raw) return null;
    return JSON.parse(raw) as TranscriptMessage[];
  } catch { return null; }
}

/**
 * Lex Legal Research Tools
 *
 * Real-time search across Australian (and international) legal databases:
 *   searchAustLII       — Australian case law, tribunal decisions, legislation summaries
 *   searchATO           — ATO rulings, interpretive decisions, tax cases, guides
 *   searchLegislation   — Federal Register of Legislation (Acts + Regulations)
 *   searchInternational — BAILII (UK), NZLII (NZ), WorldLII for comparative law
 *
 * Requires SERPER_API_KEY (serper.dev) — add to Vercel environment variables.
 * Without it every tool returns a graceful "not configured" message so Lex
 * can still answer from its training knowledge and tell the user to verify.
 */

export interface LegalSearchResult {
  title: string;
  url: string;
  snippet: string;
  source: string;
}

export interface LegalSearchResponse {
  results: LegalSearchResult[];
  query: string;
  source: string;
  error?: string;
}

async function siteSearch(
  query: string,
  site: string,
  sourceLabel: string,
  numResults = 6
): Promise<LegalSearchResponse> {
  const apiKey = process.env.SERPER_API_KEY;

  if (!apiKey) {
    return {
      results: [],
      query,
      source: sourceLabel,
      error:
        "Search API not configured — add SERPER_API_KEY to Vercel environment variables to enable live legal database search.",
    };
  }

  try {
    const res = await fetch("https://google.serper.dev/search", {
      method: "POST",
      headers: {
        "X-API-KEY": apiKey,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({ q: `site:${site} ${query}`, num: numResults }),
    });

    if (!res.ok) {
      return {
        results: [],
        query,
        source: sourceLabel,
        error: `Search returned HTTP ${res.status}`,
      };
    }

    const data = await res.json();
    const organic: Array<{ title?: string; link?: string; snippet?: string }> =
      data.organic ?? [];

    return {
      results: organic.map((r) => ({
        title: r.title ?? "",
        url: r.link ?? "",
        snippet: r.snippet ?? "",
        source: sourceLabel,
      })),
      query,
      source: sourceLabel,
    };
  } catch (err) {
    return {
      results: [],
      query,
      source: sourceLabel,
      error: String(err),
    };
  }
}

