/**
 * Chat model configuration.
 *
 * Models are resolved from environment variables using the format:
 *   "provider:model-id"
 *
 * Examples:
 *   DEFAULT_CHAT_MODEL=anthropic:claude-haiku-4-5-20251001
 *   PREMIUM_CHAT_MODEL=anthropic:claude-sonnet-4-6
 *   DEFAULT_CHAT_MODEL=openai:gpt-4o-mini
 *   PREMIUM_CHAT_MODEL=openai:gpt-4o
 *   DEFAULT_CHAT_MODEL=google:gemini-2-0-flash-001
 *   PREMIUM_CHAT_MODEL=google:gemini-2-0-pro-001
 *
 * Supported providers: "anthropic", "openai", "google"
 * The API route selects tier based on the `tier` field in the request body.
 * Default tier is "default" (cost-efficient). Use "premium" for qualified leads.
 */

import { anthropic } from "@ai-sdk/anthropic";
import { openai } from "@ai-sdk/openai";
import { google } from "@ai-sdk/google";
import type { LanguageModel } from "ai";

function resolveModel(envKey: string, fallback: string): LanguageModel {
  const value = process.env[envKey] ?? fallback;
  const sep = value.indexOf(":");

  if (sep === -1) {
    // No provider prefix — assume Anthropic
    return anthropic(value);
  }

  const provider = value.slice(0, sep);
  const modelId = value.slice(sep + 1);

  switch (provider) {
    case "anthropic":
      return anthropic(modelId);
    case "openai":
      return openai(modelId);
    case "google":
      return google(modelId);
    default:
      throw new Error(
        `[chat-config] Unknown provider "${provider}" in ${envKey}="${value}". ` +
          `Supported: "anthropic", "openai", "google".`
      );
  }
}

/**
 * Cost-efficient model for all conversations.
 * Controlled by DEFAULT_CHAT_MODEL env var.
 * Fallback: claude-haiku-4-5 (Anthropic) — set DEFAULT_CHAT_MODEL=google:gemini-2.5-flash-lite in Vercel for cheaper Google option.
 * NOTE: gemini-2.0-flash is deprecated June 1 2026 — use gemini-2.5-flash-lite instead.
 */
export function getDefaultModel(): LanguageModel {
  return resolveModel("DEFAULT_CHAT_MODEL", "anthropic:claude-haiku-4-5");
}

/**
 * High-capability model for qualified leads or complex conversations.
 * Controlled by PREMIUM_CHAT_MODEL env var.
 * Fallback: claude-sonnet-4-6
 */
export function getPremiumModel(): LanguageModel {
  return resolveModel("PREMIUM_CHAT_MODEL", "anthropic:claude-sonnet-4-6");
}

/**
 * Select model by tier. Used in the Rex API route.
 */
export function getModel(tier: "default" | "premium" = "default"): LanguageModel {
  return tier === "premium" ? getPremiumModel() : getDefaultModel();
}

/**
 * Model for Saabai's own chat (Mia / Atlas).
 * Controlled by SAABAI_CHAT_MODEL env var — completely independent of Rex model config.
 * Fallback: claude-haiku-4.5 (Anthropic only, never Google).
 */
export function getSaabaiModel(): LanguageModel {
  return resolveModel("SAABAI_CHAT_MODEL", "anthropic:claude-haiku-4-5");
}

/**
 * Analyze conversation depth to detect if escalation to premium model is needed.
 * Returns "premium" if conversation shows technical complexity or length.
 * Used for dynamic mid-conversation model switching (Gemini → Claude).
 */
export function analyzeConversationDepth(
  messages: Array<{ role: string; content: string }>
): "default" | "premium" {
  if (messages.length === 0) return "default";

  const allText = messages.map(m => m.content).join(" ").toLowerCase();

  // Technical keywords that indicate complex material science questions
  const technicalKeywords = [
    // Bonding & adhesives
    "bond", "solvent", "cement", "craze", "adhesive", "glue",
    // Thermal & mechanical
    "stress crack", "creep", "fatigue", "thermal", "expansion",
    "thermoform", "forming", "heat",
    // UV & weathering
    "uv resist", "yellow", "degrad", "weather", "outdoor durability",
    // Material properties
    "galvan", "elastomer", "filler", "reinforc", "compos",
    "hygrosc", "moisture absorb", "moisture content",
    // Fabrication
    "machine", "router", "laser cut", "cnc", "weld", "anneal",
    // Specific materials requiring depth
    "ptfe", "teflon", "creep", "virgin", "reprocess",
    "uhmwpe", "wear resist",
    "acetal", "delrin", "pom",
    // Complex comparisons
    "vs ", "versus", "difference between", "compare", "better for",
  ];

  const hasTechnicalKeyword = technicalKeywords.some(kw => allText.includes(kw));

  // Long conversation → likely escalated to complex questions
  const conversationLength = messages.length;
  const isLongConversation = conversationLength > 8;

  // Correction/confusion pattern → customer is pushing back or unclear
  const lastUserMsg = messages
    .filter(m => m.role === "user")
    .pop()?.content.toLowerCase() ?? "";

  const isCorrection =
    lastUserMsg.includes("but ") ||
    lastUserMsg.includes("actually") ||
    lastUserMsg.includes("wait") ||
    lastUserMsg.includes("no ") ||
    lastUserMsg.includes("what about") ||
    lastUserMsg.includes("instead");

  // Escalate if any factor detected
  if (hasTechnicalKeyword || isLongConversation || isCorrection) {
    return "premium";
  }

  return "default";
}

// Pipedrive CRM client — order status lookup + Rex lead creation

const PIPEDRIVE_BASE = "https://api.pipedrive.com/v1";

const STAGE_MESSAGES: Record<string, string> = {
  "New Order":                  "has been received and is in the queue — the team will get onto it shortly",
  "Waiting On Material":        "is waiting on materials to arrive before we can start cutting — we'll move it straight into production once they're in",
  "Production":                 "is currently in production",
  "Ready for Pick Up/Delivery": "is ready to go — you can come in and pick it up, or your delivery is on its way",
  "Dropship":                   "is being dispatched directly from our supplier and will be on its way to you soon",
  "Completed":                  "has been completed",
};

export interface OrderStatus {
  found: boolean;
  orderNumber?: string;
  status?: string;
  message?: string;
  error?: string;
}

/** Extract the numeric part from an order number, e.g. "HP-5089" → "5089", "PLON-36135" → "36135" */
function extractNumber(raw: string): string {
  const match = raw.match(/(\d+)$/);
  return match ? match[1] : raw;
}

/** Known order prefixes — bare numbers default to PLON- */
const KNOWN_PREFIXES = ["PLON-", "HP-", "EXP-"];

// ── Rex Lead → Pipedrive Deal ─────────────────────────────────────────────────

export interface RexLeadParams {
  name?: string;
  email?: string;
  phone?: string;
  company?: string;        // company / organisation name
  quoteDetails?: string;   // AI-extracted product details
  price?: string;          // e.g. "$185.50 Ex GST"
  priceValue?: number;     // numeric AUD
  summary?: string;        // AI conversation summary
  source?: string;         // rex_mid_chat | rex_quote_email etc.
  device?: string;         // mobile | desktop
}

/**
 * Find or create a Pipedrive person by email, then create a deal.
 * Fire-and-forget — never throws, never blocks lead capture.
 * Controlled by:
 *   PIPEDRIVE_API_TOKEN  — existing token
 *   PIPEDRIVE_PIPELINE_ID — pipeline for Rex leads (defaults to 1)
 *   PIPEDRIVE_STAGE_ID    — initial stage ID (defaults to first stage found)
 */
export async function createRexDeal(params: RexLeadParams): Promise<void> {
  const token = process.env.PIPEDRIVE_API_TOKEN;
  if (!token) return;

  const pipelineId = process.env.PIPEDRIVE_PIPELINE_ID ?? "1";
  const stageId    = process.env.PIPEDRIVE_STAGE_ID;

  try {
    // 1. Find or create organisation
    let orgId: number | undefined;

    if (params.company) {
      const orgSearchRes = await fetch(
        `${PIPEDRIVE_BASE}/organizations/search?term=${encodeURIComponent(params.company)}&exact_match=false&limit=1&api_token=${token}`
      );
      if (orgSearchRes.ok) {
        const orgSearchData = await orgSearchRes.json();
        const existingOrg = orgSearchData?.data?.items?.[0]?.item;
        if (existingOrg?.id) {
          orgId = existingOrg.id;
        }
      }

      if (!orgId) {
        const orgCreateRes = await fetch(`${PIPEDRIVE_BASE}/organizations?api_token=${token}`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ name: params.company }),
        });
        if (orgCreateRes.ok) {
          const orgCreateData = await orgCreateRes.json();
          orgId = orgCreateData?.data?.id;
        }
      }
    }

    // 2. Find or create person
    let personId: number | undefined;

    if (params.email) {
      // Search for existing person by email
      const searchRes = await fetch(
        `${PIPEDRIVE_BASE}/persons/search?term=${encodeURIComponent(params.email)}&fields=email&exact_match=true&limit=1&api_token=${token}`
      );
      if (searchRes.ok) {
        const searchData = await searchRes.json();
        const existing = searchData?.data?.items?.[0]?.item;
        if (existing?.id) {
          personId = existing.id;
        }
      }

      // Create person if not found
      if (!personId) {
        const createRes = await fetch(`${PIPEDRIVE_BASE}/persons?api_token=${token}`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            name:   params.name ?? params.email,
            email:  [{ value: params.email, primary: true }],
            phone:  params.phone ? [{ value: params.phone, primary: true }] : undefined,
            org_id: orgId,
          }),
        });
        if (createRes.ok) {
          const createData = await createRes.json();
          personId = createData?.data?.id;
        }
      }
    }

    // 2. Build deal title — concise enough to scan in a pipeline view
    const shortQuote = params.quoteDetails
      ? params.quoteDetails.split("\n")[0].slice(0, 50)
      : "Rex Quote";
    const priceLabel = params.price ?? (params.priceValue ? `$${params.priceValue}` : "");
    const customerLabel = params.name ?? params.email ?? "Anonymous";
    const dealTitle = `Rex: ${customerLabel} — ${shortQuote}${priceLabel ? ` — ${priceLabel}` : ""}`;

    // 3. Create deal
    const dealBody: Record<string, unknown> = {
      title:       dealTitle,
      pipeline_id: Number(pipelineId),
      value:       params.priceValue ?? 0,
      currency:    "AUD",
      status:      "open",
    };
    if (stageId)  dealBody.stage_id  = Number(stageId);
    if (personId) dealBody.person_id = personId;
    if (orgId)    dealBody.org_id    = orgId;

    const dealRes = await fetch(`${PIPEDRIVE_BASE}/deals?api_token=${token}`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(dealBody),
    });
    if (!dealRes.ok) return;

    const dealData = await dealRes.json();
    const dealId: number | undefined = dealData?.data?.id;
    if (!dealId) return;

    // 4. Add a note with full context
    const noteLines = [
      `📥 Source: ${params.source ?? "rex"}${params.device ? ` (${params.device})` : ""}`,
      params.company ? `🏢 Company: ${params.company}` : null,
      params.quoteDetails ? `📦 Quote: ${params.quoteDetails}` : null,
      priceLabel ? `💰 Price: ${priceLabel} Ex GST` : null,
      params.summary ? `\n💬 Summary: ${params.summary}` : null,
    ].filter(Boolean).join("\n");

    await fetch(`${PIPEDRIVE_BASE}/notes?api_token=${token}`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        content:  noteLines,
        deal_id:  dealId,
        pinned_to_deal_flag: true,
      }),
    });
  } catch {
    // Never throw — CRM write failure must not affect lead capture
  }
}

export async function lookupOrder(orderNumber: string): Promise<OrderStatus> {
  const token = process.env.PIPEDRIVE_API_TOKEN;
  if (!token) return { found: false, error: "Order lookup unavailable" };

  const raw = orderNumber.trim().toUpperCase();
  const hasPrefix = KNOWN_PREFIXES.some(p => raw.startsWith(p));
  // Full normalised term (for display and fallback matching)
  const term = hasPrefix ? raw : `PLON-${raw}`;
  // Numeric part only — used as the search term to match across all order types
  const numericPart = extractNumber(term);

  try {
    // Search the full Pipedrive database (no fields filter) using just the number
    // so HP-, EXP-, and PLON- deals all surface regardless of how their titles are structured
    const searchRes = await fetch(
      `${PIPEDRIVE_BASE}/deals/search?term=${encodeURIComponent(numericPart)}&exact_match=false&limit=20&api_token=${token}`
    );
    if (!searchRes.ok) return { found: false, error: `Search failed (${searchRes.status})` };

    const searchData = await searchRes.json();
    const items: any[] = searchData?.data?.items ?? [];

    // Prefer a deal whose title contains the full term (e.g. "HP-5089")
    // Fall back to any deal whose title contains just the numeric part
    let match = items.find(i =>
      typeof i.item?.title === "string" &&
      i.item.title.toUpperCase().includes(term)
    );
    if (!match) {
      match = items.find(i =>
        typeof i.item?.title === "string" &&
        i.item.title.includes(numericPart)
      );
    }

    if (!match) return { found: false };

    // Use the deal title as the display label if it's more descriptive than our normalised term
    const dealTitle: string = match.item?.title ?? term;

    // Stage name is returned directly in the search result — no extra API call needed
    const stageName: string = match.item?.stage?.name ?? "";

    if (!stageName) {
      return { found: true, orderNumber: dealTitle, status: "Unknown", message: `Order ${dealTitle} was found but we couldn't read the current status — please call us on (07) 5564 6744 for a quick update.` };
    }

    // Display name overrides — fix formatting for stages with slashes or awkward casing
    const DISPLAY_NAMES: Record<string, string> = {
      "Ready for Pick Up/Delivery": "Ready For Pick-Up Or Delivery",
    };
    const titleCased = DISPLAY_NAMES[stageName] ??
      stageName.replace(/\w+/g, w => w.charAt(0).toUpperCase() + w.slice(1));
    const detail = STAGE_MESSAGES[stageName];
    const message = detail
      ? `Order **${dealTitle}** — **${titleCased}** — ${detail}.`
      : `Order **${dealTitle}** is currently **${titleCased}**.`;

    return { found: true, orderNumber: dealTitle, status: stageName, message };
  } catch (err) {
    return { found: false, error: String(err) };
  }
}

const WOO_URL = process.env.WOOCOMMERCE_URL!;
const WOO_KEY = process.env.WOOCOMMERCE_CONSUMER_KEY!;
const WOO_SECRET = process.env.WOOCOMMERCE_CONSUMER_SECRET!;
const PLON_ORIGIN = "https://www.plasticonline.com.au";
const PLON_PRICE_API = `${PLON_ORIGIN}/wp-json/plon/v1/price`;

function auth() {
  return "Basic " + Buffer.from(`${WOO_KEY}:${WOO_SECRET}`).toString("base64");
}

async function callPriceApi(params: {
  productId: number;
  variationId: number;
  color: string;
  thickness: string;
}): Promise<{ unit_price: number; custom_multiplier: number; constraints: any } | { error: string }> {
  try {
    const qs = new URLSearchParams({
      product_id: String(params.productId),
      variation_id: String(params.variationId),
      color: params.color,
      thickness: params.thickness,
    });
    const res = await fetch(`${PLON_PRICE_API}?${qs}`);
    if (!res.ok) return { error: `Price API returned ${res.status}` };
    const json = await res.json() as any;
    if (json.unit_price) return { unit_price: json.unit_price, custom_multiplier: json.custom_multiplier ?? 1, constraints: json.constraints };
    return { error: `Unexpected response: ${JSON.stringify(json)}` };
  } catch (err) {
    return { error: `Price API call failed: ${String(err)}` };
  }
}

async function fetchVariations(productId: number) {
  try {
    const allVars: any[] = [];
    const pageSize = 100;
    let page = 1;

    // Paginate until all variations are fetched (products like acrylic have 100+)
    while (true) {
      const url = `${WOO_URL}/wp-json/wc/v3/products/${productId}/variations?per_page=${pageSize}&page=${page}`;
      const res = await fetch(url, { headers: { Authorization: auth() } });
      if (!res.ok) break;
      const vars = await res.json() as any[];
      if (!vars.length) break;
      allVars.push(...vars);
      if (vars.length < pageSize) break; // last page
      page++;
    }

    return allVars.map((v) => {
      // Extract CPC unit price from meta_data if present
      const meta: Record<string, any> = {};
      if (Array.isArray(v.meta_data)) {
        for (const m of v.meta_data) {
          meta[m.key] = m.value;
        }
      }
      return {
        variation_id: v.id,
        attributes: (v.attributes as any[]).map((a) => ({ name: a.name, option: a.option })),
        in_stock: v.stock_status === "instock",
        meta,
      };
    });
  } catch {
    return [];
  }
}

export interface WooOrder {
  id: number;
  number: string;        // formatted order number e.g. "PLON-48376"
  date_created: string;
  status: string;
  total: string;
  currency: string;
  billing: {
    first_name: string;
    last_name: string;
    email: string;
  };
  line_items: Array<{ name: string; quantity: number; total: string }>;
  meta_data: Array<{ key: string; value: unknown }>;
}

export async function fetchRecentOrders(days = 60): Promise<WooOrder[]> {
  try {
    if (!WOO_URL || !WOO_KEY || !WOO_SECRET) return [];
    const after = new Date(Date.now() - days * 24 * 60 * 60 * 1000).toISOString();
    const url = `${WOO_URL}/wp-json/wc/v3/orders?per_page=100&after=${encodeURIComponent(after)}&status=processing,completed&orderby=date&order=desc`;
    const res = await fetch(url, {
      headers: { Authorization: auth() },
      next: { revalidate: 300 }, // cache 5 min
    });
    if (!res.ok) return [];
    return res.json() as Promise<WooOrder[]>;
  } catch {
    return [];
  }
}

export async function searchProducts(query: string) {
  try {
    const url = `${WOO_URL}/wp-json/wc/v3/products?search=${encodeURIComponent(query)}&per_page=5&status=publish`;
    const res = await fetch(url, { headers: { Authorization: auth() } });
    if (!res.ok) return { error: `WooCommerce ${res.status}` };

    const products = await res.json() as any[];
    if (!products.length) return { results: [], message: "No products found for that search." };

    const results = await Promise.all(products.map(async (p) => {
      const isVariable = p.type === "variable";
      const variations = isVariable ? await fetchVariations(p.id) : [];

      return {
        product_id: p.id,
        name: p.name,
        type: p.type,
        in_stock: p.stock_status === "instock",
        url: p.permalink,
        imageUrl: (p.images as any[])?.[0]?.src ?? "",
        categories: (p.categories as any[])?.map((c) => c.name).join(", ") ?? "",
        variations,
      };
    }));

    return { results };
  } catch (err) {
    return { error: String(err) };
  }
}

export async function calculateCutToSizePrice(params: {
  productId: number;
  variationId: number;
  color: string;
  thickness: string;
  widthMm: number;
  heightMm: number;
  quantity?: number;
  applyMultiplier?: boolean; // true for acrylic/polycarbonate; other materials have it baked into unit_price
}) {
  const result = await callPriceApi(params);
  if ("error" in result) return result;

  const { unit_price, custom_multiplier, constraints } = result;
  const qty = params.quantity ?? 1;

  // Validate dimensions
  const maxW = constraints?.max_width ?? 9999;
  const maxH = constraints?.max_height ?? 9999;
  if (params.widthMm > maxW || params.heightMm > maxH) {
    return {
      error: `That exceeds our max sheet size of ${maxW} by ${maxH}mm — our team can quote for larger cuts.`,
    };
  }

  const areaSqm = (params.widthMm / 1000) * (params.heightMm / 1000);
  // PLON's price API returns custom_multiplier for all products, but only acrylic/polycarbonate
  // actually apply it in their CTS calculator — other materials have the CTS rate baked into unit_price.
  const multiplier = (params.applyMultiplier ?? false) ? (custom_multiplier ?? 1) : 1;
  const unitTotal = unit_price * multiplier * areaSqm;
  const total = Math.round(unitTotal * qty * 100) / 100;

  return {
    price_per_sqm: `AUD $${unit_price.toFixed(2)} /m²`,
    dimensions: `${params.widthMm}mm by ${params.heightMm}mm`,
    area_sqm: Math.round(areaSqm * 1000) / 1000,
    quantity: qty,
    unit_total: `AUD $${unitTotal.toFixed(2)} Ex GST`,
    total: `AUD $${total.toFixed(2)} Ex GST`,
    note: "GST added at checkout.",
    product_url: `${PLON_ORIGIN}/?p=${params.productId}`,
    add_to_cart_url: `${PLON_ORIGIN}/?add-to-cart=${params.variationId}`,
  };
}

/**
 * Client configuration for the Saabai Client Portal.
 *
 * Clients are defined entirely via environment variables — no code changes
 * needed when adding a new client.
 *
 * Required env vars per client (replace N with 1, 2, 3, …):
 *   SAABAI_CLIENT_N_ID          — Unique slug, no spaces (e.g. "plasticonline")
 *   SAABAI_CLIENT_N_NAME        — Display name (e.g. "PlasticOnline")
 *   SAABAI_CLIENT_N_EMAIL       — Login email (e.g. "admin@plasticonline.com.au")
 *   SAABAI_CLIENT_N_PASSWORD    — Plain-text password (store securely in Vercel)
 *   SAABAI_CLIENT_N_DASHBOARD   — Dashboard path (e.g. "/rex-dashboard")
 *
 * Example for PlasticOnline:
 *   SAABAI_CLIENT_1_ID=plasticonline
 *   SAABAI_CLIENT_1_NAME=PlasticOnline
 *   SAABAI_CLIENT_1_EMAIL=admin@plasticonline.com.au
 *   SAABAI_CLIENT_1_PASSWORD=yourpassword
 *   SAABAI_CLIENT_1_DASHBOARD=/rex-dashboard
 */

export interface ClientConfig {
  id: string;
  name: string;
  email: string;
  password: string;
  dashboardUrl: string;
}

export function loadClients(): ClientConfig[] {
  const clients: ClientConfig[] = [];
  let i = 1;

  while (true) {
    const id = process.env[`SAABAI_CLIENT_${i}_ID`];
    if (!id) break;

    const email    = process.env[`SAABAI_CLIENT_${i}_EMAIL`]    ?? "";
    const password = process.env[`SAABAI_CLIENT_${i}_PASSWORD`] ?? "";
    const dashboard = process.env[`SAABAI_CLIENT_${i}_DASHBOARD`] ?? "/";
    const name     = process.env[`SAABAI_CLIENT_${i}_NAME`]     ?? id;

    if (email && password) {
      clients.push({ id, name, email, password, dashboardUrl: dashboard });
    }
    i++;
  }

  return clients;
}

export function findClientByCredentials(
  clients: ClientConfig[],
  email: string,
  password: string
): ClientConfig | null {
  const normalised = email.trim().toLowerCase();
  return (
    clients.find(
      c => c.email.toLowerCase() === normalised && c.password === password
    ) ?? null
  );
}

