@import "tailwindcss";

/* ─── Saabai Brand Colour System ───────────────────────────────────────────
   Colours sampled directly from /public/brand/saabai-logo.png.
   All colour decisions flow from here.

   Sampled values:
     Logo background:  #0b092e  (deep indigo-navy)
     Helix teal:       #62c5d1  (primary brand accent)
     Mid blue:         #1f4dc5  (secondary accent)
     Deep blue:        #0915a4  (gradient / glow anchor)
     Text:             #ffffff  (wordmark)
   ────────────────────────────────────────────────────────────────────────── */

:root {
  /* Backgrounds — DARK THEME (original brand colours) */
  --saabai-bg:              #0b092e;
  --saabai-surface:         #0f0d35;
  --saabai-surface-raised:  #13113d;
  --saabai-nav:             #0b092e;

  /* Brand accents */
  --saabai-teal:            #62c5d1;
  --saabai-teal-bright:     #7dd9e3;
  --saabai-blue:            #1f4dc5;
  --saabai-blue-deep:       #0915a4;

  /* Glows */
  --saabai-glow:            #62c5d108;   /* Very subtle teal                 */
  --saabai-glow-mid:        #62c5d118;   /* Mid teal glow                    */
  --saabai-glow-strong:     #62c5d130;   /* Stronger teal glow               */

  /* Borders */
  --saabai-border:          #1e1b4b;     /* Deep indigo border               */
  --saabai-border-accent:   #62c5d140;   /* Teal accent border               */

  /* Text */
  --saabai-text:            #ffffff;     /* White                            */
  --saabai-text-muted:      #a5b4fc;     /* Soft indigo-white                */
  --saabai-text-dim:        #7c8db5;     /* Dimmed blue-grey                 */

  /* Legacy */
  --background: var(--saabai-bg);
  --foreground: var(--saabai-text);
}

/* ─── Tailwind v4 Theme Registration ────────────────────────────────────── */

@theme inline {
  --color-background:             var(--background);
  --color-foreground:             var(--foreground);

  --color-saabai-bg:              var(--saabai-bg);
  --color-saabai-surface:         var(--saabai-surface);
  --color-saabai-surface-raised:  var(--saabai-surface-raised);

  --color-saabai-teal:            var(--saabai-teal);
  --color-saabai-teal-bright:     var(--saabai-teal-bright);
  --color-saabai-blue:            var(--saabai-blue);
  --color-saabai-blue-deep:       var(--saabai-blue-deep);

  --color-saabai-glow:            var(--saabai-glow);
  --color-saabai-glow-mid:        var(--saabai-glow-mid);
  --color-saabai-glow-strong:     var(--saabai-glow-strong);

  --color-saabai-border:          var(--saabai-border);
  --color-saabai-border-accent:   var(--saabai-border-accent);

  --color-saabai-text:            var(--saabai-text);
  --color-saabai-text-muted:      var(--saabai-text-muted);
  --color-saabai-text-dim:        var(--saabai-text-dim);

  --font-sans: var(--font-geist-sans);
  --font-mono: var(--font-geist-mono);
}

/* ─── Base ───────────────────────────────────────────────────────────────── */

body {
  background: #ffffff;
  color: #1f2937;
  font-family: var(--font-geist-sans), system-ui, sans-serif;
  -webkit-font-smoothing: antialiased;
}

/* Mission Control dashboard background — pure white */
.min-h-screen { 
  background-color: #ffffff !important;
}

/* ─── News ticker animation ─────────────────────────────────────────────── */

@keyframes news-ticker {
  0%   { transform: translateX(0); }
  100% { transform: translateX(-50%); }
}

/* ─── Utilities ─────────────────────────────────────────────────────────── */

/* Gradient text — used on hero headline accent */
.text-gradient {
  background: linear-gradient(135deg, var(--saabai-text) 0%, var(--saabai-teal) 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

/* Teal number glow — used on stat numbers */
.stat-glow {
  text-shadow:
    0 0 40px var(--saabai-glow-mid),
    0 0 80px var(--saabai-glow);
}

/* Teal top-border gradient for featured cards */
.card-featured::before {
  content: "";
  position: absolute;
  inset: 0;
  border-top: 1px solid var(--saabai-border-accent);
  pointer-events: none;
}
